always @ (posedge ap_clk) begin
    if (ap_rst_n_inv == 1'b1) begin
        ap_CS_fsm <= ap_ST_fsm_state1;
    end else begin
        ap_CS_fsm <= ap_NS_fsm;
    end
end

always @ (posedge ap_clk) begin
    if (ap_rst_n_inv == 1'b1) begin
        ap_done_reg <= 1'b0;
    end else begin
        if ((ap_continue == 1'b1)) begin
            ap_done_reg <= 1'b0;
        end else if (((1'b0 == ap_block_state3_on_subcall_done) & (1'b1 == ap_CS_fsm_state3))) begin
            ap_done_reg <= 1'b1;
        end
    end
end

always @ (posedge ap_clk) begin
    if (ap_rst_n_inv == 1'b1) begin
        ap_sync_reg_grp_norm_sum_impl_fu_132_ap_done <= 1'b0;
    end else begin
        if (((1'b0 == ap_block_state3_on_subcall_done) & (1'b1 == ap_CS_fsm_state3))) begin
            ap_sync_reg_grp_norm_sum_impl_fu_132_ap_done <= 1'b0;
        end else if ((grp_norm_sum_impl_fu_132_ap_done == 1'b1)) begin
            ap_sync_reg_grp_norm_sum_impl_fu_132_ap_done <= 1'b1;
        end
    end
end

always @ (posedge ap_clk) begin
    if (ap_rst_n_inv == 1'b1) begin
        ap_sync_reg_grp_norm_sum_impl_fu_132_ap_ready <= 1'b0;
    end else begin
        if (((1'b0 == ap_block_state3_on_subcall_done) & (1'b1 == ap_CS_fsm_state3))) begin
            ap_sync_reg_grp_norm_sum_impl_fu_132_ap_ready <= 1'b0;
        end else if ((grp_norm_sum_impl_fu_132_ap_ready == 1'b1)) begin
            ap_sync_reg_grp_norm_sum_impl_fu_132_ap_ready <= 1'b1;
        end
    end
end

always @ (posedge ap_clk) begin
    if (ap_rst_n_inv == 1'b1) begin
        grp_norm_sum_impl_fu_132_ap_start_reg <= 1'b0;
    end else begin
        if (((1'b1 == ap_CS_fsm_state2) | ((ap_sync_grp_norm_sum_impl_fu_132_ap_ready == 1'b0) & (1'b1 == ap_CS_fsm_state3)))) begin
            grp_norm_sum_impl_fu_132_ap_start_reg <= 1'b1;
        end else if ((grp_norm_sum_impl_fu_132_ap_ready == 1'b1)) begin
            grp_norm_sum_impl_fu_132_ap_start_reg <= 1'b0;
